// Process workflow activate/deactivate/status requests
// Calls n8n internal API to control other workflows

const item = $input.item.json;
const body = item.body || item;
const action = body.action;
const workflowId = body.workflow_id;

if (!action || !workflowId) {
  return { json: { success: false, error: 'Missing action or workflow_id. Send {action: activate|deactivate|status, workflow_id: string}' } };
}

const apiUrl = $env.N8N_API_URL || 'http://localhost:5678/api/v1';
const apiKey = $env.N8N_API_KEY;

if (!apiKey) {
  return { json: { success: false, error: 'N8N_API_KEY env var not set' } };
}

const headers = { 'X-N8N-API-KEY': apiKey };

try {
  if (action === 'activate') {
    await this.helpers.httpRequest({
      method: 'POST',
      url: apiUrl + '/workflows/' + workflowId + '/activate',
      headers: headers,
      json: true
    });
    return { json: { success: true, workflow_id: workflowId, active: true, action: 'activated' } };
  }

  if (action === 'deactivate') {
    await this.helpers.httpRequest({
      method: 'POST',
      url: apiUrl + '/workflows/' + workflowId + '/deactivate',
      headers: headers,
      json: true
    });
    return { json: { success: true, workflow_id: workflowId, active: false, action: 'deactivated' } };
  }

  if (action === 'status') {
    const wf = await this.helpers.httpRequest({
      method: 'GET',
      url: apiUrl + '/workflows/' + workflowId,
      headers: headers,
      json: true
    });
    return { json: { success: true, workflow_id: workflowId, name: wf.name, active: wf.active } };
  }

  return { json: { success: false, error: 'Unknown action: ' + action + '. Use activate, deactivate, or status.' } };
} catch(e) {
  return { json: { success: false, error: e.message } };
}
